var canvas=document.getElementById('canvas');
var ctx=canvas.getContext('2d');
ctx.scale(2,2);
ctx.imageSmoothingEnabled = false;
let solutionAnimating = false;
let solutionDistance = 0;
let solutionTotalLength = 0;
let solutionSpeed = 2.4;
let solutionSegments = [];


let drawMode = false;
let isDrawing = false;
let userPath = []; 
const startPoint = { x: 122, y: 5 }; 
const endPoint = { x: 122, y: 240 };  

// Pripravi dele poti, da se lahko resitev lepo animira.
function pripraviResitev() {
    solutionSegments = [];
    solutionTotalLength = 0;

    if (!path || path.length < 2) return;

    for (let i = 1; i < path.length; i++) {
        const [x1, y1] = path[i - 1];
        const [x2, y2] = path[i];
        const len = Math.hypot(x2 - x1, y2 - y1);

        if (len > 0) {
            solutionSegments.push({
                x1, y1, x2, y2, len
            });
            solutionTotalLength += len;
        }
    }
}

// Iz sekund naredi zapis casa MM:SS.
function formatCasSkupaj(sekunde) {
    const min = Math.floor(sekunde / 60);
    const sec = sekunde % 60;
    return (min < 10 ? "0" + min : min) + ":" + (sec < 10 ? "0" + sec : sec);
}

// Pobere najboljsi cas iz localStorage, ce je ze shranjen.
function naloziNajboljsiCas() {
    const raw = parseInt(localStorage.getItem(BEST_TIME_KEY), 10);
    if (Number.isFinite(raw) && raw >= 0) return raw;
    return null;
}

// Osvezi napis za najboljsi cas.
function osveziNajboljsiCasPrikaz() {
    bestTimeEl.textContent = bestTime === null ? "--:--" : formatCasSkupaj(bestTime);
}

// Posodobi stevec pobranih kovancev.
function osveziScorePrikaz() {
    scoreEl.textContent = `${collectedCoins}/${coins.length}`;
}

// Ce je cas boljsi od rekorda, ga shrani.
function shraniNajboljsiCas(casSekunde) {
    if (bestTime === null || casSekunde < bestTime) {
        bestTime = casSekunde;
        localStorage.setItem(BEST_TIME_KEY, String(casSekunde));
        osveziNajboljsiCasPrikaz();
        return true;
    }
    return false;
}

// Na novo razmece kovance po poti in vse resetira.
function ponastaviKovance() {
    coins = [];
    collectedCoins = 0;

    const tocke = path.slice(3, -3);
    if (tocke.length === 0) {
        osveziScorePrikaz();
        return;
    }

    const steviloKovancev = Math.min(MAX_COINS, tocke.length);
    const korak = tocke.length / (steviloKovancev + 1);

    for (let i = 1; i <= steviloKovancev; i++) {
        const idx = Math.floor(i * korak);
        const [cx, cy] = tocke[Math.min(idx, tocke.length - 1)];

        if (
            Math.hypot(cx - startPoint.x, cy - startPoint.y) > 12 &&
            Math.hypot(cx - endPoint.x, cy - endPoint.y) > 12
        ) {
            coins.push({ x: cx, y: cy, collected: false });
        }
    }

    osveziScorePrikaz();
}

// Narise samo kovance, ki se niso pobrani.
function narisiKovance() {
    for (const coin of coins) {
        if (coin.collected) continue;
        ctx.beginPath();
        ctx.fillStyle = "#ffcf33";
        ctx.strokeStyle = "#b57a00";
        ctx.lineWidth = 1.5;
        ctx.arc(coin.x, coin.y, 3.8, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
    }
}

// Ce si blizu kovanca, ga pobere.
function poberiKovanec(px, py) {
    for (const coin of coins) {
        if (!coin.collected && Math.hypot(px - coin.x, py - coin.y) < 8) {
            coin.collected = true;
            collectedCoins++;
            osveziScorePrikaz();
        }
    }
}


var x = 120;
var y = 0;
var starx = 120;
var stary = 0;
var size = 8; 
var speed = 2;
var igralecVid = false; 
var totalTime = 90; 
