var startBtn = document.getElementById("start");
var scoreEl = document.getElementById("score");
var bestTimeEl = document.getElementById("best-time");
var timerInterval;
const BEST_TIME_KEY = "deadlyGreenBestTime";
const MAX_COINS = 6;
let coins = [];
let collectedCoins = 0;
let bestTime = naloziNajboljsiCas();
osveziNajboljsiCasPrikaz();
ponastaviKovance();

