// Pogleda, ce bi na tej poziciji zadel steno.
function jeStena(nx, ny){
    for(let i=0; i<size; i++){
        for(let j=0; j<size; j++){
            let d = ctx.getImageData((nx+i)*2, (ny+j)*2, 1, 1).data;
            if(d[0] === 0 && d[1] === 128 && d[2] === 0){
                return true; 
            }
        }
    }
    return false; 
}

document.addEventListener("keydown", function(e){
    if(!igralecVid) return;
    let nx = x, ny = y;

    if(e.key === "w") ny -= speed;
    if(e.key === "s") ny += speed;
    if(e.key === "a") nx -= speed;
    if(e.key === "d") nx += speed;

    if(!jeStena(nx, ny)){
        x = nx;
        y = ny;
        poberiKovanec(x, y);
        if (Math.hypot(x - endPoint.x, y - endPoint.y) < 8) {
            igralecVid = false;
            clearInterval(timerInterval);
            const porabljenCas = 90 - totalTime;
            const jeRekord = shraniNajboljsiCas(porabljenCas);

            Swal.fire({
                title: 'Zmaga!',
                html: `
                    <div style="line-height: 1.55;">
                        <p>Cas: <strong>${formatCasSkupaj(porabljenCas)}</strong></p>
                        <p>Kovanci: <strong>${collectedCoins}/${coins.length}</strong></p>
                        ${jeRekord ? '<p><strong>Nov najboljsi cas!</strong></p>' : ''}
                    </div>
                `,
                icon: 'success',
                confirmButtonText: 'Super!',
                confirmButtonColor: '#50d89d',
                heightAuto: false
            });
        }
    }
    else {
        igralecVid = false;         
        clearInterval(timerInterval); 
        x = starx;
        y = stary;
        totalTime = 90;
        updateTimerDisplay(); 

        Swal.fire({
            title: 'Zadel si steno!',
            text: 'Vrnil si se na začetek.',
            icon: 'error',
            timer: 2000, 
            timerProgressBar: true,
            showConfirmButton: false,
            heightAuto: false
        });
    }
});



// Izrise celo trenutno stanje igre na platnu.
function igrlc(){
    ctx.clearRect(0,0,500,500);
    narisiTrenutniLabirint(ctx);
    narisiKovance();

    solution(); 
    ctx.fillStyle = "orange";
    ctx.beginPath(); ctx.arc(startPoint.x, startPoint.y, 6, 0, Math.PI*2); ctx.fill();

    ctx.fillStyle = "red";
    ctx.beginPath(); ctx.arc(endPoint.x, endPoint.y, 6, 0, Math.PI*2); ctx.fill();

    if (userPath.length > 1) {
        ctx.beginPath();
        ctx.strokeStyle = "#4a90e2";
        ctx.lineWidth = 3;
        ctx.lineJoin = "round";
        ctx.moveTo(userPath[0].x, userPath[0].y);
        for (let i = 1; i < userPath.length; i++) {
            ctx.lineTo(userPath[i].x, userPath[i].y);
        }
        ctx.stroke();
    }
    if(igralecVid){
        ctx.drawImage(igralecSlika, x, y, size, size);
    }
}


const drawBtn = document.getElementById("draw");

// Pretvori polozaj miske v koordinate na canvasa.
function dobiMiskoNaPlatnu(e) {
    const rect = canvas.getBoundingClientRect();
    const logicnaSirina = canvas.width / 2;
    const logicnaVisina = canvas.height / 2;

    return {
        x: ((e.clientX - rect.left) / rect.width) * logicnaSirina,
        y: ((e.clientY - rect.top) / rect.height) * logicnaVisina
    };
}

drawBtn.addEventListener("click", () => {
    drawMode = true;
    igralecVid = false; 
    x = starx;
    y = stary;
    userPath = [];
    ponastaviKovance();
    canvas.style.cursor = "crosshair";

    totalTime = 30;
    updateTimerDisplay();
    if(timerInterval) clearInterval(timerInterval);
    timerInterval = setInterval(timer, 1000);
});

canvas.addEventListener("mousedown", (e) => {
    if (!drawMode) return;
    const { x: mx, y: my } = dobiMiskoNaPlatnu(e);

    if (Math.hypot(mx - startPoint.x, my - startPoint.y) < 15) {
        isDrawing = true;
        userPath.push({ x: mx, y: my });
    }
});

canvas.addEventListener("mousemove", (e) => {
    if (!isDrawing || !drawMode) return;
    const { x: mx, y: my } = dobiMiskoNaPlatnu(e);

    if (!jePikaNaSteni(mx, my)) {
        userPath.push({ x: mx, y: my });
        poberiKovanec(mx, my);
        
        if (Math.hypot(mx - endPoint.x, my - endPoint.y) < 8) {
            isDrawing = false;
            drawMode = false;
            canvas.style.cursor = "default";
            clearInterval(timerInterval);
            const porabljenCas = 30 - totalTime;
            const jeRekord = shraniNajboljsiCas(porabljenCas);

            Swal.fire({
                title: 'Cilj dosežen!',
                html: `
                    <div style="line-height: 1.55;">
                        <p>Cas: <strong>${formatCasSkupaj(porabljenCas)}</strong></p>
                        <p>Kovanci: <strong>${collectedCoins}/${coins.length}</strong></p>
                        ${jeRekord ? '<p><strong>Nov najboljsi cas!</strong></p>' : ''}
                    </div>
                `,
                icon: 'success',
                confirmButtonText: 'Odlično',
                confirmButtonColor: '#50d89d',
                heightAuto: false
            });
        }
    } else {
        isDrawing = false;
        drawMode = false;
        canvas.style.cursor = "pointer";
        userPath = [];
        clearInterval(timerInterval);
        totalTime = 30;         
        updateTimerDisplay();     
        Swal.fire({
            title: 'Zadel si steno!',
            text: 'Vrnil si se na začetek.',
            icon: 'error',
            timer: 2000, 
            timerProgressBar: true,
            showConfirmButton: false,
            heightAuto: false
        });
    }
});

window.addEventListener("mouseup", () => { isDrawing = false; });

// Hitri check, ce je tocka na zeleni steni.
function jePikaNaSteni(px, py) {
    let d = ctx.getImageData(px * 2, py * 2, 1, 1).data;
    return (d[0] === 0 && d[1] === 128 && d[2] === 0);
}

document.getElementById("auto").addEventListener("click", () => {
    if (solutionSegments.length === 0) {
        pripraviResitev();
    }
    drawMode = false;
    x = starx;
    y = stary;
    userPath = [];
    ponastaviKovance();
    solutionDistance = 0;
    solutionAnimating = true;
    clearInterval(timerInterval);
    igralecVid = false;         
    totalTime = 90;         
    updateTimerDisplay();     
});

// Odsteva cas; ko ga zmanjka, je game over.
function timer(){
    if(totalTime > 0){
        totalTime--;
        updateTimerDisplay(); 
    } else {
        clearInterval(timerInterval);
        igralecVid = false;         
        x = starx;                 
        y = stary;
        totalTime = 90;         
        updateTimerDisplay();         

        Swal.fire({
            title: 'Čas je potekel!',
            text: 'Preveč časa si porabil. Poskusi znova!',
            icon: 'warning',
            confirmButtonText: 'V redu',
            heightAuto: false
        });
    }
}
// Samo osvezi prikaz preostalega casa.
function updateTimerDisplay() {
    let min = Math.floor(totalTime / 60);
    let sec = totalTime % 60;
    timerEl.textContent = 
        (min < 10 ? "0" + min : min) + ":" + (sec < 10 ? "0" + sec : sec);
}

// Glavna zanka, ki se stalno vrti in rise igro.
function gameLoop() {
    igrlc();
    requestAnimationFrame(gameLoop);
}

requestAnimationFrame(gameLoop);

startBtn.addEventListener("click", function(){
    igralecVid = true;
    drawMode = false;
    x = starx;
    y = stary;
    userPath = [];
    ponastaviKovance();
    solutionAnimating = false;
    totalTime = 90;
    updateTimerDisplay();
    if(timerInterval) clearInterval(timerInterval);
    timerInterval = setInterval(timer, 1000);
});

// Korak za korakom narise animirano resitev poti.
function solution(){
    if(!solutionAnimating) return;
    if(solutionSegments.length === 0 || solutionTotalLength === 0) return;

    solutionDistance = Math.min(solutionDistance + solutionSpeed, solutionTotalLength);

    ctx.beginPath();
    ctx.strokeStyle = "red";
    ctx.lineWidth = 3;
    ctx.lineCap = "round";
    ctx.lineJoin = "round";
    ctx.moveTo(solutionSegments[0].x1, solutionSegments[0].y1);

    let preostanek = solutionDistance;

    for (let i = 0; i < solutionSegments.length; i++) {
        const seg = solutionSegments[i];

        if (preostanek >= seg.len) {
            ctx.lineTo(seg.x2, seg.y2);
            preostanek -= seg.len;
        } else {
            const t = preostanek / seg.len;
            const ix = seg.x1 + (seg.x2 - seg.x1) * t;
            const iy = seg.y1 + (seg.y2 - seg.y1) * t;
            ctx.lineTo(ix, iy);
            break;
        }
    }

    ctx.stroke();

    if(solutionDistance >= solutionTotalLength){
        solutionAnimating = false;
    }
}

